// CLX B2C v2.1 — Build Smart Scan List
//
// Inputs (via $() lookups):
//   Fetch Active Clients → rows from clients where active=true
//   Fetch Scan Tracker   → rows from scan_query_tracker
//
// Logic:
//   1. Derive the active (industry, product_type) set from clients.
//      Fallback to ALL hardcoded industries if no clients are found
//      (initial-setup safety net).
//   2. Expand to all GTA cities (expansion cities rule).
//   3. Cross with query templates for each active industry.
//   4. Deduplicate on (search_query, city).
//   5. Apply smart-scan filter:
//        - no tracker row               → scan (first time)
//        - paused=false                 → scan
//        - paused=true, scanned <7d ago → skip
//        - paused=true, scanned ≥7d ago → scan (weekly retry)
//
// Logs a summary so operators can see savings in the execution log.

const GTA_CITIES = ['Toronto', 'Mississauga', 'Brampton', 'Vaughan', 'Markham'];
const WEEKLY_RETRY_MS = 7 * 24 * 60 * 60 * 1000;

const QUERY_TEMPLATES = {
  'moving_services': [
    'local moving company', 'long distance movers', 'residential movers',
    'apartment movers', 'piano movers', 'furniture movers', 'moving and storage',
    'moving help wanted', 'last minute movers', 'same day moving service',
    'office movers', 'commercial movers', 'business relocation services',
    'new home movers'
  ],
  'insurance': [
    'auto insurance broker', 'home insurance broker', 'life insurance agent',
    'health insurance broker', 'commercial insurance broker',
    'business liability insurance', 'small business insurance broker',
    'key person insurance agent', 'new homeowner insurance'
  ],
  'dental': [
    'dentist', 'cosmetic dentist', 'pediatric dentist',
    'emergency dentist', 'walk in dental clinic',
    'family dentist accepting new patients'
  ],
  'beauty': [
    'hair salon', 'beauty salon', 'nail salon'
  ],
  'cleaning_services': [
    'residential cleaning service', 'house cleaning', 'maid service',
    'cleaner wanted', 'deep cleaning service'
  ],
  'construction': [
    'home renovation contractor', 'kitchen renovation', 'bathroom renovation',
    'roofing contractor', 'landscaping contractor', 'general contractor'
  ]
};

const INDUSTRY_LABELS = {
  'moving_services':   'moving services',
  'insurance':         'insurance',
  'dental':            'dental',
  'beauty':            'hair and beauty',
  'cleaning_services': 'cleaning services',
  'construction':      'construction'
};

// ---- 1. Pull active clients ----
function readItems(nodeName) {
  try {
    const items = $(nodeName).all();
    if (!items || items.length === 0) return [];
    // Unwrap httpRequest fullResponse shape
    const first = items[0].json || {};
    if (Array.isArray(first.body)) return first.body;
    // Otherwise each item is already a row
    return items.map(i => i.json).filter(x => x && typeof x === 'object');
  } catch (e) {
    console.log('[CLX v2.1] readItems(' + nodeName + ') error: ' + e.message);
    return [];
  }
}

const clients    = readItems('Fetch Active Clients');
const trackerRaw = readItems('Fetch Scan Tracker');

console.log('[CLX v2.1] Active clients: ' + clients.length);
console.log('[CLX v2.1] Tracker rows:   ' + trackerRaw.length);

// Index tracker by (query||city)
const tracker = {};
for (const t of trackerRaw) {
  if (!t || !t.search_query || !t.city) continue;
  tracker[t.search_query + '||' + t.city] = t;
}

// ---- 2. Derive active industries from clients (fallback to ALL) ----
const activeProductTypes = new Set();
for (const c of clients) {
  if (c && c.product_type && QUERY_TEMPLATES[c.product_type]) {
    activeProductTypes.add(c.product_type);
  } else if (c && c.industry) {
    for (const [pt, label] of Object.entries(INDUSTRY_LABELS)) {
      if (label.toLowerCase() === String(c.industry).toLowerCase()) {
        activeProductTypes.add(pt);
        break;
      }
    }
  }
}

if (activeProductTypes.size === 0) {
  console.log('[CLX v2.1] No active clients matched templates — using full hardcoded set');
  for (const pt of Object.keys(QUERY_TEMPLATES)) activeProductTypes.add(pt);
}

console.log('[CLX v2.1] Active product types: ' + Array.from(activeProductTypes).join(', '));

// ---- 3. Build + dedupe the candidate scan list ----
const candidates = [];
const seen = new Set();
for (const pt of activeProductTypes) {
  const templates = QUERY_TEMPLATES[pt] || [];
  const industryLabel = INDUSTRY_LABELS[pt] || pt;
  for (const city of GTA_CITIES) {
    for (const q of templates) {
      const searchQuery = q + ' in ' + city + ' Canada';
      const key = searchQuery + '||' + city;
      if (seen.has(key)) continue;
      seen.add(key);
      candidates.push({
        city: city,
        industry: industryLabel,
        product_type: pt,
        search_query: searchQuery
      });
    }
  }
}

// ---- 4. Apply smart-scan filter ----
const now = Date.now();
const scanList = [];
let skippedPaused = 0;
let scheduledRetry = 0;
let firstTime = 0;
let active = 0;

for (const c of candidates) {
  const t = tracker[c.search_query + '||' + c.city];
  if (!t) {
    firstTime++;
    scanList.push(c);
    continue;
  }
  if (!t.paused) {
    active++;
    scanList.push(c);
    continue;
  }
  const lastMs = t.last_scanned_at ? Date.parse(t.last_scanned_at) : 0;
  if (!lastMs || (now - lastMs) >= WEEKLY_RETRY_MS) {
    scheduledRetry++;
    scanList.push(c);
    continue;
  }
  skippedPaused++;
}

console.log('[CLX v2.1] Scan plan — candidates: ' + candidates.length
          + ' | first-time: ' + firstTime
          + ' | active: ' + active
          + ' | weekly-retry: ' + scheduledRetry
          + ' | skipped(paused<7d): ' + skippedPaused
          + ' | TOTAL TO SCAN: ' + scanList.length);

if (scanList.length === 0) {
  console.log('[CLX v2.1] Nothing to scan today — all queries paused & within retry window.');
}

return scanList.map(item => ({ json: item }));

// CLX B2C v2.1 — Handle Maps Error
const ctx = $('Split In Batches').item.json;
const raw = $input.item.json || {};

const httpError = raw.error || raw.errorMessage || null;
const statusCode = raw.statusCode || (raw.headers && raw.headers.status) || null;

const body = raw.body || raw;
const googleError = body && body.error && (body.error.message || body.error.status) ? body.error : null;

const httpFailed = (typeof statusCode === 'number' && statusCode >= 400);
const hasError = Boolean(httpError || googleError || httpFailed);

if (hasError) {
  const code = googleError ? String(googleError.code || googleError.status || 'google_error')
             : httpFailed ? String(statusCode)
             : 'unknown';
  const message = googleError ? (googleError.message || googleError.status || 'Google Places error')
                : httpError ? String(httpError)
                : 'HTTP ' + statusCode;
  console.log('[CLX v2.1] Maps error for "' + ctx.search_query + '": ' + message);
  return {
    json: {
      has_error: true,
      error_code: code,
      error_message: message,
      input_data: ctx,
      ...ctx
    }
  };
}

return {
  json: {
    has_error: false,
    ...ctx,
    places: (body && body.places) || []
  }
};

// CLX B2C v2.1 — Parse Places Results
const data = $input.item.json || {};
const ctx = $('Split In Batches').item.json;
const places = Array.isArray(data.places) ? data.places : [];

if (places.length === 0) {
  return { json: { businesses: [], count: 0, results_found: 0, ...ctx } };
}

const businesses = [];
const seen = {};

for (const place of places) {
  const name = (place.displayName && place.displayName.text) ? place.displayName.text : '';
  if (!name) continue;
  const key = name.toLowerCase();
  if (seen[key]) continue;
  seen[key] = true;

  businesses.push({
    name: name,
    formatted_address: place.formattedAddress || '',
    phone: place.nationalPhoneNumber || '',
    website: place.websiteUri || '',
    place_id: place.id || '',
    city: ctx.city,
    industry: ctx.industry,
    product_type: ctx.product_type,
    search_query: ctx.search_query
  });
}

console.log('[CLX v2.1] Parsed ' + businesses.length + ' businesses for query: ' + ctx.search_query);

return {
  json: {
    businesses: businesses,
    count: businesses.length,
    results_found: businesses.length,
    ...ctx
  }
};

// CLX B2C v2.1 — No Results path
// Emits a tracker-ready payload with new_leads=0 so Update Scan Tracker
// can record this query as a zero-result scan.
const ctx = $input.item.json || {};
return {
  json: {
    _tracker: {
      p_search_query: ctx.search_query,
      p_city:         ctx.city,
      p_industry:     ctx.industry,
      p_product_type: ctx.product_type,
      p_new_leads:    0
    }
  }
};

// CLX B2C v2.1 — Process Each Business
const data = $('Parse Places Results').item.json;
const businesses = data.businesses || [];
if (businesses.length === 0) return [];

return businesses.map(biz => ({
  json: {
    p_full_name: null,
    p_email: null,
    p_phone: biz.phone || null,
    p_company: biz.name,
    p_job_title: 'Owner',
    p_industry: biz.industry,
    p_city: biz.city,
    p_source: 'google_maps_discovery',
    p_lead_status: 'New Lead',
    p_product_type: biz.product_type,
    p_notes: 'Places ID: ' + (biz.place_id || '') + ' | Address: ' + (biz.formatted_address || '') + (biz.website ? ' | Website: ' + biz.website : ''),
    _scan_city: biz.city,
    _scan_query: biz.search_query,
    _scan_industry: biz.industry,
    _scan_product_type: biz.product_type
  }
}));

// CLX B2C v2.1 — Parse RPC Response
const input = $input.item.json || {};
const ctx = $('Process Each Business').item.json || {};
const company = ctx.p_company || 'unknown';

const httpErr = input.error || input.errorMessage || null;
const statusCode = typeof input.statusCode === 'number' ? input.statusCode : null;
const httpFailed = httpErr || (statusCode !== null && statusCode >= 400);

if (httpFailed) {
  const message = httpErr ? String(httpErr) : ('HTTP ' + statusCode);
  console.log('[CLX v2.1] RPC failure for ' + company + ': ' + message);
  return {
    json: {
      status: 'error',
      error_code: httpErr ? 'rpc_error' : String(statusCode),
      error_message: message,
      company: company,
      client_id: null,
      client_matched: false,
      _scan_city: ctx._scan_city,
      _scan_query: ctx._scan_query,
      _scan_industry: ctx._scan_industry,
      _scan_product_type: ctx._scan_product_type
    }
  };
}

const body = input.body !== undefined ? input.body : input;
let rec = null;
if (Array.isArray(body)) rec = body[0] || null;
else if (body && typeof body === 'object') rec = body;

const status = rec && rec.status ? String(rec.status).toLowerCase() : 'unknown';
const id = rec && rec.id ? rec.id : null;
const client_id = rec && rec.client_id ? rec.client_id : null;
const client_matched = rec && rec.client_matched === true;

console.log('[CLX v2.1] RPC ' + status + ' for ' + company
          + (id ? ' (id=' + id + ')' : '')
          + (client_id ? ' → client=' + client_id : ' → unassigned'));

return {
  json: {
    status: status,
    id: id,
    company: company,
    client_id: client_id,
    client_matched: client_matched,
    _scan_city: ctx._scan_city,
    _scan_query: ctx._scan_query,
    _scan_industry: ctx._scan_industry,
    _scan_product_type: ctx._scan_product_type
  }
};

// CLX B2C v2.1 — Prep Tracker (Inserted branch)
// Builds the upsert_scan_tracker payload for a successful insert.
const ctx = $('Parse RPC Response').item.json || {};
return {
  json: {
    _tracker: {
      p_search_query: ctx._scan_query,
      p_city:         ctx._scan_city,
      p_industry:     ctx._scan_industry,
      p_product_type: ctx._scan_product_type,
      p_new_leads:    1
    }
  }
};

// CLX B2C v2.1 — Prep Tracker (Duplicate / Error branch)
// Emits an upsert_scan_tracker payload with new_leads=0 so the
// tracker counts this as a non-productive outcome.
const ctx = $('Parse RPC Response').item.json || {};
return {
  json: {
    _tracker: {
      p_search_query: ctx._scan_query,
      p_city:         ctx._scan_city,
      p_industry:     ctx._scan_industry,
      p_product_type: ctx._scan_product_type,
      p_new_leads:    0
    }
  }
};

// CLX B2C v2.1 — Scan Complete Summary
const resp = $('Fetch Today Scan Log').item.json || {};
const body = resp.body !== undefined ? resp.body : resp;
const rows = Array.isArray(body) ? body : [];

let results = 0, inserted = 0, duplicates = 0, errors = 0;
for (const r of rows) {
  results    += Number(r.results_found       || 0);
  inserted   += Number(r.new_leads_inserted  || 0);
  duplicates += Number(r.duplicates_skipped  || 0);
  errors     += Number(r.errors              || 0);
}

const summary = {
  workflow: 'CLX-B2C-Discovery',
  version: 'v2.1',
  run_completed_at: new Date().toISOString(),
  scan_log_rows: rows.length,
  totals: {
    results_found: results,
    new_leads_inserted: inserted,
    duplicates_skipped: duplicates,
    errors: errors
  },
  estimated_api_spend_usd: Number((rows.length * 0.032).toFixed(2)),
  message: '[CLX v2.1] Daily scan complete — ' + inserted + ' new leads, ' + duplicates + ' duplicates, ' + errors + ' errors across ' + rows.length + ' logged batches.'
};

console.log(summary.message);
return { json: summary };
